package com.example.documentviewer;

import android.content.ContentResolver;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.graphics.pdf.PdfRenderer;
import android.net.Uri;
import android.os.Bundle;
import android.os.ParcelFileDescriptor;
import android.view.ViewGroup;
import android.widget.ImageView;
import android.widget.Toast;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

import java.io.IOException;
import java.io.InputStream;

public class DocumentViewerActivity extends AppCompatActivity {

    private ImageView imageView;
    private ParcelFileDescriptor pdfFileDescriptor;
    private PdfRenderer pdfRenderer;
    private PdfRenderer.Page currentPage;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        imageView = new ImageView(this);
        imageView.setLayoutParams(new ViewGroup.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));
        imageView.setAdjustViewBounds(true);
        imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);
        setContentView(imageView);

        handleIntent();
    }

    @Override
    protected void onNewIntent(android.content.Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent();
    }

    private void handleIntent() {
        Uri fileUri = null;
        if (getIntent() != null) {
            fileUri = getIntent().getData();
        }

        if (fileUri == null) {
            Toast.makeText(this, "No document URI provided", Toast.LENGTH_LONG).show();
            finish();
            return;
        }

        String mimeType = getContentResolver().getType(fileUri);
        if (mimeType == null) {
            String path = fileUri.toString().toLowerCase();
            if (path.endsWith(".pdf")) {
                mimeType = "application/pdf";
            } else if (path.endsWith(".png") || path.endsWith(".jpg") || path.endsWith(".jpeg") || path.endsWith(".gif") || path.endsWith(".bmp") || path.endsWith(".webp")) {
                mimeType = "image/*";
            }
        }

        if ("application/pdf".equals(mimeType)) {
            displayPdf(fileUri);
        } else if (mimeType != null && mimeType.startsWith("image/")) {
            displayImage(fileUri);
        } else {
            Toast.makeText(this, "Unsupported document type", Toast.LENGTH_LONG).show();
            finish();
        }
    }

    private void displayImage(Uri uri) {
        closePdfResources();
        try (InputStream inputStream = getContentResolver().openInputStream(uri)) {
            if (inputStream == null) {
                Toast.makeText(this, "Unable to open image", Toast.LENGTH_LONG).show();
                finish();
                return;
            }
            Bitmap bitmap = BitmapFactory.decodeStream(inputStream);
            if (bitmap == null) {
                Toast.makeText(this, "Failed to decode image", Toast.LENGTH_LONG).show();
                finish();
                return;
            }
            imageView.setImageBitmap(bitmap);
        } catch (IOException e) {
            Toast.makeText(this, "Error opening image", Toast.LENGTH_LONG).show();
            finish();
        }
    }

    private void displayPdf(Uri uri) {
        closePdfResources();
        try {
            ContentResolver resolver = getContentResolver();
            pdfFileDescriptor = resolver.openFileDescriptor(uri, "r");
            if (pdfFileDescriptor == null) {
                Toast.makeText(this, "Unable to open PDF", Toast.LENGTH_LONG).show();
                finish();
                return;
            }

            pdfRenderer = new PdfRenderer(pdfFileDescriptor);
            if (pdfRenderer.getPageCount() <= 0) {
                Toast.makeText(this, "PDF has no pages", Toast.LENGTH_LONG).show();
                finish();
                return;
            }

            currentPage = pdfRenderer.openPage(0);
            Bitmap bitmap = Bitmap.createBitmap(
                    currentPage.getWidth(),
                    currentPage.getHeight(),
                    Bitmap.Config.ARGB_8888
            );
            bitmap.eraseColor(0xFFFFFFFF);
            currentPage.render(bitmap, null, null, PdfRenderer.Page.RENDER_MODE_FOR_DISPLAY);
            imageView.setImageBitmap(bitmap);
        } catch (IOException e) {
            Toast.makeText(this, "Error opening PDF", Toast.LENGTH_LONG).show();
            finish();
        }
    }

    private void closePdfResources() {
        if (currentPage != null) {
            currentPage.close();
            currentPage = null;
        }
        if (pdfRenderer != null) {
            pdfRenderer.close();
            pdfRenderer = null;
        }
        if (pdfFileDescriptor != null) {
            try {
                pdfFileDescriptor.close();
            } catch (IOException ignored) {
            }
            pdfFileDescriptor = null;
        }
    }

    @Override
    protected void onDestroy() {
        closePdfResources();
        super.onDestroy();
    }
}